import os
import pickle
import cloudstorage

def get_latest_model_version_path(base_path):
    client = cloudstorage.Client()
    bucket = client.get_bucket(base_path)
    models = [blob.name for blob in bucket.list_blobs()]
    if not models:
        raise Exception("No models found in given path.")
    latest_model = max(models)
    return os.path.join(base_path, latest_model)

def load_model_from_cloud():
    model_base_path = os.getenv('MODEL_BASE_PATH')
    if not model_base_path:
        raise Exception("MODEL_BASE_PATH environment variable not set")
    latest_model_path = get_latest_model_version_path(model_base_path)
    client = cloudstorage.Client()
    bucket = client.get_bucket(model_base_path)
    blob = bucket.get_blob(latest_model_path)
    model_data = blob.download_as_bytes()
    model = pickle.loads(model_data)
    return model

def main():
    model = load_model_from_cloud()
    # Further code to utilize the model for inference

if __name__ == "__main__":
    main()